import uuid
from flask import Flask, request, jsonify, redirect, url_for

app = Flask(__name__)

# In-memory storage for client applications (for simplicity)
# client_id: {client_secret: "...", redirect_uris: ["..."], user_id: "..."}
CLIENTS = {
    "test_client": {
        "client_secret": "test_secret",
        "redirect_uris": ["http://localhost:5001/callback", "http://127.0.0.1:5001/callback"],
        "user_id": "test_user_id" # This is just an example. In a real system, you'd have user registration.
    }
}

# In-memory storage for authorization codes
# auth_codes[code] = user_id
AUTH_CODES = {}

# In-memory storage for access tokens
# access_tokens[token] = {user_id: "...", client_id: "..."}
ACCESS_TOKENS = {}

@app.route('/')
def index():
    return "<h1>OAuth 2.0 Authorization Server</h1>"

@app.route('/authorize')
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    state = request.args.get('state')

    if not all([client_id, redirect_uri, response_type]):
        return jsonify({"error": "Missing required parameters"}), 400

    if client_id not in CLIENTS:
        return jsonify({"error": "Invalid client_id"}), 400

    if redirect_uri not in CLIENTS[client_id]["redirect_uris"]:
        return jsonify({"error": "Invalid redirect_uri"}), 400

    if response_type != 'code':
        return jsonify({"error": "Unsupported response_type"}), 400

    # Simulate user login/consent - for an internal system, this might be pre-approved
    # For this example, we'll directly generate a code for the hardcoded user
    # In a real app, this would involve a login page where the user grants permission.
    user_id = CLIENTS[client_id]["user_id"] # Get the user associated with the client for simplicity

    # Generate an authorization code
    auth_code = str(uuid.uuid4())
    AUTH_CODES[auth_code] = user_id

    # Redirect back to the client with the authorization code
    redirect_to = f"{redirect_uri}?code={auth_code}"
    if state:
        redirect_to += f"&state={state}"

    return redirect(redirect_to)

@app.route('/token', methods=['POST'])
def token():
    grant_type = request.form.get('grant_type')
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri')
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    if not all([grant_type, code, redirect_uri, client_id, client_secret]):
        return jsonify({"error": "Missing required parameters"}), 400

    if grant_type != 'authorization_code':
        return jsonify({"error": "Unsupported grant_type"}), 400

    if client_id not in CLIENTS:
        return jsonify({"error": "Invalid client_id"}), 401

    if CLIENTS[client_id]["client_secret"] != client_secret:
        return jsonify({"error": "Invalid client_secret"}), 401

    if redirect_uri not in CLIENTS[client_id]["redirect_uris"]:
        return jsonify({"error": "Invalid redirect_uri"}), 400

    user_id = AUTH_CODES.get(code)
    if not user_id:
        return jsonify({"error": "Invalid authorization code"}), 400

    # For internal systems, we might allow multiple exchanges.
    # If not, you would remove the code after first use: del AUTH_CODES[code]

    # Generate an access token
    access_token = str(uuid.uuid4())
    ACCESS_TOKENS[access_token] = {"user_id": user_id, "client_id": client_id}

    return jsonify({
        "access_token": access_token,
        "token_type": "Bearer",
        # "expires_in": 3600, # In a real system, you'd add expiration
        # "scope": "read write" # In a real system, you'd add scopes
    })

# Example endpoint to validate an access token
@app.route('/validate_token', methods=['POST'])
def validate_token():
    access_token = request.form.get('access_token')

    if not access_token:
        return jsonify({"error": "Missing access_token"}), 400

    token_info = ACCESS_TOKENS.get(access_token)
    if not token_info:
        return jsonify({"error": "Invalid or expired access token"}), 401

    return jsonify({
        "status": "valid",
        "user_id": token_info["user_id"],
        "client_id": token_info["client_id"]
    })

